import { useParams } from "react-router-dom" 
import personajes from '../personajes'


export default function Personaje() {

    const { id } = useParams();
    
    let personajeEncontrado = null;

    Object.values(personajes).forEach((item)=> {
        const personaje = item.find((p) => p.id === id)
        if(personaje){
            personajeEncontrado = personaje;
        }
    })

    if(!personajeEncontrado){
        return <p>No se ha encontrado el personaje</p>
    }

    return (
        <div id="personaje" key={id}>
            <div className="personaje-contenido">
                <h2>{personajeEncontrado.nombre}</h2>
                <p><b>Descripcion:</b> {personajeEncontrado.descripcion}</p>
                <p><b>Poder: </b>{personajeEncontrado.poder}</p>
                <p><b>Categoria: </b>{personajeEncontrado.categoria}</p>
                <img className="imgPersonaje"  src={`/imgs/${personajeEncontrado.imagen}`} />
            </div>
        </div>
        
    )
}