import { useState } from "react";
import Navbar from "../componentes/Navbar";
import { Button, Modal, Box, Typography } from '@mui/material';


export default function Login(){

    const [open, setOpen] = useState(false);

    return (
        <div className="login">
            <Navbar/>
            <div className="login-container">
                <div className="login-formulario">
                    <div className="mitad-imagen">
                    </div>
                    <div className="mitad-datos">
                        <form method="post">
                            <h2>Iniciar sesión</h2>
                            <input type="text" name="usuario" id="usuario" placeholder="Usuario"/><br/>
                            <input type="password" name="password" id="password" placeholder="Password"/><br/>
                            <button className="btnLogin" type="submit">Iniciar sessión</button><br/>
                        </form>
                        <button className="btnRegistro" onClick={()=> setOpen(true)} >¡Regístrate!</button>
                            <Modal 
                                open={open}
                                onClose={()=> setOpen(false)}
                                aria-labelledby="modal-modal-title"
                                aria-describedby="modal-modal-description"
                                style={{
                                    display: 'flex',
                                    alignItems: 'center',
                                    justifyContent: 'center'
                                }}
                                >
                                    <Box className="registro">
                                        <div className="registro-datos">
                                            <h2>Registro</h2>
                                            <label>Nombre de usuario</label>
                                            <input type="text" name="usuario" id="usuario" placeholder="Usuario"/><br/>
                                            <label>Contraseña</label>
                                            <input type="password" name="password" id="password" placeholder="Password"/><br/>
                                            <label>Teléfono</label>
                                            <input type="number" name="telefono" id="telefono" placeholder="Telefono"/><br/>
                                            <label>Correo</label>
                                            <input type="email" name="email" id="email" placeholder="Correo"/><br/>
                                            <button className="btnRegistro2" >¡Regístrate!</button>
                                        </div>
                                    </Box>
                                </Modal>
                    </div>
                </div>
            </div>
        </div>

    )
}