import { useState, useEffect } from "react";
import { Form, Link, useLoaderData, useSubmit } from "react-router-dom";



export default function Sidebar({personajes}){
    
    // Funcion para comparar si dentro del objeto personajes hay algo que ha escrito el usuario
    const filtrarPersonajes = (nombres, personajes) => {
        if(!nombres){
            return personajes;
        }
        return personajes.filter((pers) => pers.nombre.toLowerCase().includes(nombres));
    }

    // useState que guarda lo que escribe el usuario en el buscador
    const [nombres, setNombres] = useState("");


    // Esta variable llama a la funcion filtrarPersonajes y sirve para mostrar los personajes filtrados
    let personajesFiltrados = filtrarPersonajes(nombres,personajes)

    

    // Funcion para ocultar el buscador al entrar a Home
    const isHome = () => {
        return personajes.some(pers => pers.categoria === "null");
      }      


    return(
        <div id="sidebar">
                <img src={`/imgs/onepiece_logo.png`} className='logo'/>
                    <Form id="search-form" role="search" >
                        <input
                        id="buscador"
                        type="search"
                        placeholder="Buscar"
                        name="q"
                        className={isHome() ? "isHome" : ""}
                        onChange={(e) => setNombres(e.target.value.toLowerCase())}
                        />
                    </Form>
                <nav>
                    <ul>
                         {personajesFiltrados.map(pers =>(
                            <li key={pers.id}>
                                <Link to={`${pers.id}`}>
                                    <>
                                        {pers.nombre}
                                    </>
                                </Link>
                            </li>
                        ))} 
                    </ul>
                </nav>
            </div>
    )
}