import './App.css';
import React from 'react';
import * as ReactDOM from "react-dom/client";

import {
  createBrowserRouter, 
  RouterProvider,
  Route,
  createRoutesFromElements
} from "react-router-dom";

import personajes from './personajes';
import Home from './routes/Home';
import Index from './routes/Index';
import Personaje from './routes/Personaje';
import Login from './routes/Login';
import Error from './routes/Error';


const router = createBrowserRouter(
      createRoutesFromElements(
        <>
          <Route path='/' element={<Home personaje={personajes.null}/>} errorElement={<Error />}>
              <Route index={true} element={<Index/>}/>
          </Route>
          <Route path='/heroes' element={<Home personaje={personajes.heroes}/>} errorElement={<Error />}>
              <Route path='/heroes/:id' element={<Personaje />}/>
          </Route>
          <Route path='/villanos' element={<Home personaje={personajes.villanos}/>} errorElement={<Error />}>
              <Route path='/villanos/:id' element={<Personaje />}/>
          </Route>
          <Route path='/leyendas' element={<Home personaje={personajes.leyendas}/>} errorElement={<Error />}>
              <Route path='/leyendas/:id' element={<Personaje />}/>
          </Route>
          <Route path='/login' element={<Login />}/>
        </>

      )
)

function App() {
  return (
    <RouterProvider router={router} />
  )
}

export default App;
